// 質問IDをキーとした検索インデックス
export const SCORING_BY_QID: Record<string, readonly ScoringRecord[]> = (() => {
  const map: Record<string, ScoringRecord[]> = {};
  for (const r of SCORING_DB) {
    (map[r.question_id] ??= []).push(r);
  }
  return map;
})();

// 特定の質問・選択肢の採点キーを取得
export function getScoringRecord(qid: string, option: string): ScoringRecord | undefined {
  return SCORING_BY_QID[qid]?.find((r) => r.option === option);
}
